/**
 * Story wrappers for LoadingOverlay — used by Playwright CT.
 *
 * LoadingOverlay reads gameActive and activeChunks from useGameStore.
 * It only shows when gameActive=true and fades out once activeChunks is non-empty.
 * We need to carefully control the store to test different visual states.
 */
import { useEffect } from 'react';
import { useGameStore } from '../../stores/gameStore';
import { LoadingOverlay } from './LoadingOverlay';

/**
 * Shows the loading overlay in its active loading state.
 * gameActive=true, activeChunks empty => stays visible.
 */
export function LoadingOverlayVisible() {
  useEffect(() => {
    useGameStore.setState({
      gameActive: true,
      activeChunks: new Map(),
    });
  }, []);

  return <LoadingOverlay />;
}

/**
 * Loading overlay when game is not active — should not render.
 */
export function LoadingOverlayHidden() {
  useEffect(() => {
    useGameStore.setState({
      gameActive: false,
      activeChunks: new Map(),
    });
  }, []);

  return (
    <div data-testid="loading-hidden-wrapper">
      <LoadingOverlay />
    </div>
  );
}
